import{C as t,o as r,c as l,a5 as s,E as n}from"./chunks/framework.CW28V7p_.js";const p=JSON.parse('{"title":"7. Treasury multisig (Squads)","description":"","frontmatter":{},"headers":[],"relativePath":"module-8/7-treasury-multisig.md","filePath":"module-8/7-treasury-multisig.md","lastUpdated":1780937944000}'),o={name:"module-8/7-treasury-multisig.md"},c=Object.assign(o,{setup(d){const e={id:"m8-7-treasury",title:"🧠 Mini-check: Treasury multisig",intro:"2 питання.",questions:[{type:"explain",q:"Чому Squads multisig стандарт для validator org treasury?",ideal:`Single private key для org treasury = single point of failure. One compromise → all funds gone. One key holder departure → access lost.

Squads multisig:
1. N-of-M threshold (наприклад 3-of-5): need 3 signatures з 5 keys для operation
2. Distribute keys серед team members (CEO, CTO, ops lead, legal, board member)
3. Compromise one key = insufficient. Need to compromise 3+ simultaneously
4. One member departure: revoke their key, others still operational
5. On-chain auditable: всі actions transparent у blockchain history

Use cases для LumLabs:
- Holding cold withdrawer authorities для vote accounts
- Operator income wallet (collected commission)
- Treasury holdings (USDC, JTO, etc.)
- Long-term cold storage validator earnings

Setup time: ~30 min initial. Per-TX overhead: extra 1-2 sec для collecting signatures.`,explanation:"Module 8.7."},{type:"mcq",q:"Best practice для Squads setup?",options:["3-of-5 з each key on different hardware wallet","2-of-3 acceptable для smaller orgs","Threshold > 50% members (3-of-5, 4-of-7) для security","Single member can sign (1-of-N) defeats purpose"],correct:[0,1,2,3],explanation:"Усі правильні. Module 8.7."}]};return(h,a)=>{const i=t("Quiz");return r(),l("div",null,[a[0]||(a[0]=s(`<h1 id="_7-treasury-multisig-squads" tabindex="-1">7. Treasury multisig (Squads) <a class="header-anchor" href="#_7-treasury-multisig-squads" aria-label="Permalink to &quot;7. Treasury multisig (Squads)&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Squads</strong> — standard Solana multisig wallet. N-of-M threshold signing replaces single private key. Required для serious org treasury management. Used для cold withdrawer authority, treasury holdings, validator earnings cold storage.</p><h2 id="чому-multisig" tabindex="-1">Чому multisig <a class="header-anchor" href="#чому-multisig" aria-label="Permalink to &quot;Чому multisig&quot;">​</a></h2><p>Single private key risks:</p><ul><li><strong>Compromise</strong> = all funds gone</li><li><strong>Lost key</strong> = locked funds forever</li><li><strong>Team member departure</strong> = trust assumption broken</li><li><strong>Audit</strong> = no transparency про who signed what</li></ul><p>Multisig (e.g., 3-of-5):</p><ul><li>One key compromised = insufficient</li><li>One member departs = revoke key, continue with rest</li><li>All actions on-chain visible</li><li>Defense in depth</li></ul><h2 id="squads-basics" tabindex="-1">Squads basics <a class="header-anchor" href="#squads-basics" aria-label="Permalink to &quot;Squads basics&quot;">​</a></h2><p><strong>Squads</strong> = Solana smart contract programs implementing multisig + governance:</p><ul><li>Creates <strong>vault account</strong> (PDA) holding funds</li><li>Defines <strong>members</strong> (their pubkeys) + <strong>threshold</strong></li><li>TXs propose-vote-execute workflow</li><li>Members vote через UI (squads.so)</li></ul><h3 id="n-of-m-choices" tabindex="-1">N-of-M choices <a class="header-anchor" href="#n-of-m-choices" aria-label="Permalink to &quot;N-of-M choices&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setup</th><th>Use case</th></tr></thead><tbody><tr><td><strong>2-of-3</strong></td><td>Small team, sufficient для basic</td></tr><tr><td><strong>3-of-5</strong></td><td>Standard для validator orgs</td></tr><tr><td><strong>4-of-7</strong></td><td>Larger orgs, higher security</td></tr><tr><td><strong>5-of-9</strong></td><td>Foundations, very large orgs</td></tr></tbody></table><p>Rule of thumb: threshold &gt; 50% members. Below 50% = insufficient security.</p><h3 id="member-keys" tabindex="-1">Member keys <a class="header-anchor" href="#member-keys" aria-label="Permalink to &quot;Member keys&quot;">​</a></h3><p>Кожен member key MUST бути:</p><ul><li>На окремому hardware wallet (Ledger preferred)</li><li>Different physical locations / people</li><li>Different geographic regions якщо possible</li><li>Documented у secure team wiki who holds what</li></ul><h2 id="setup-process" tabindex="-1">Setup process <a class="header-anchor" href="#setup-process" aria-label="Permalink to &quot;Setup process&quot;">​</a></h2><h3 id="_1-create-squad" tabindex="-1">1. Create Squad <a class="header-anchor" href="#_1-create-squad" aria-label="Permalink to &quot;1. Create Squad&quot;">​</a></h3><p>Через <a href="https://squads.so" target="_blank" rel="noreferrer">squads.so</a>:</p><ol><li>Connect wallet (any member)</li><li>&quot;Create Squad&quot;</li><li>Set name (e.g., &quot;LumLabs Treasury&quot;)</li><li>Add members (their pubkeys)</li><li>Set threshold (e.g., 3)</li><li>Confirm + sign creation TX</li></ol><p>Output: Squad&#39;s <strong>vault address</strong> = treasury pubkey.</p><h3 id="_2-fund-the-vault" tabindex="-1">2. Fund the vault <a class="header-anchor" href="#_2-fund-the-vault" aria-label="Permalink to &quot;2. Fund the vault&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Send SOL to vault</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transfer</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SQUAD_VAULT_ADDRES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">S</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-unfunded-recipient</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Або token transfer</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spl-token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transfer</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">USDC_MIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 50000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SQUAD_VAULT_ADDRES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">S</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Vault address — standard Solana address, accepts будь-які incoming transfers.</p><h3 id="_3-use-as-withdrawer-authority" tabindex="-1">3. Use as withdrawer authority <a class="header-anchor" href="#_3-use-as-withdrawer-authority" aria-label="Permalink to &quot;3. Use as withdrawer authority&quot;">​</a></h3><p>When creating vote account:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-vote-account</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    vote-keypair.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    validator-keypair.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SQUAD_VAULT_ADDRES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">S</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # ← Squad&#39;s vault as withdrawer</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    --commission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span></code></pre></div><p>Withdrawer = Squad vault. Any withdraw operation вимагає 3+ members signing через Squads UI.</p><h3 id="_4-document-everything" tabindex="-1">4. Document everything <a class="header-anchor" href="#_4-document-everything" aria-label="Permalink to &quot;4. Document everything&quot;">​</a></h3><p>Шara team wiki з:</p><ul><li>Squad name + vault address</li><li>Member list + pubkeys + key holders</li><li>Threshold + voting rules</li><li>Emergency recovery procedures</li><li>Squad UI link</li></ul><h2 id="per-tx-workflow" tabindex="-1">Per-TX workflow <a class="header-anchor" href="#per-tx-workflow" aria-label="Permalink to &quot;Per-TX workflow&quot;">​</a></h2><p>Коли потрібно execute operation (e.g., withdraw vote rent):</p><ol><li><strong>Propose</strong>: any member proposes TX через Squads UI</li><li><strong>Vote</strong>: other members review + approve (sign на UI)</li><li><strong>Reach threshold</strong>: коли N members approved → TX ready</li><li><strong>Execute</strong>: anyone can hit &quot;Execute&quot; button → TX submits on-chain</li></ol><p>Time: ~1-2 days typical (members need time to review + sign).</p><p>Для urgent operations — preset workflows можна automate (recurring withdraws, etc.).</p><h2 id="squads-programs" tabindex="-1">Squads programs <a class="header-anchor" href="#squads-programs" aria-label="Permalink to &quot;Squads programs&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Squads V4: SQDS4ep65T869zMMBKyuUq6aD6EgTu8psMjkvj52pCf</span></span></code></pre></div><p>Open-source, audited. Used by Jito, Marinade, Helius, тощо.</p><h2 id="use-cases-для-lumlabs" tabindex="-1">Use cases для LumLabs <a class="header-anchor" href="#use-cases-для-lumlabs" aria-label="Permalink to &quot;Use cases для LumLabs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>Pattern</th></tr></thead><tbody><tr><td>Cold withdrawer for vote accounts</td><td>Squad 3-of-5 ✅</td></tr><tr><td>Treasury (USDC, JTO, JitoSOL holdings)</td><td>Squad 3-of-5 ✅</td></tr><tr><td>Operator income (commission collected)</td><td>Squad 2-of-3 (smaller threshold OK для warm)</td></tr><tr><td>Validator identity keypair</td><td>NOT multisig (used by validator software, must be single key)</td></tr><tr><td>Vote authority keypair</td><td>NOT multisig (used by validator software)</td></tr></tbody></table><p>⚠️ Validator software requires single private key files. Cannot use multisig для identity/vote authority. Multisig тільки for cold/treasury operations.</p><h2 id="migration-single-key-→-multisig" tabindex="-1">Migration: single key → multisig <a class="header-anchor" href="#migration-single-key-→-multisig" aria-label="Permalink to &quot;Migration: single key → multisig&quot;">​</a></h2><p>Якщо у тебе single withdrawer authority зараз:</p><ol><li>Create Squad</li><li>Use <code>solana vote-authorize-withdrawer-checked</code> команду для transfer authority до Squad vault</li><li>Verify Squad now authority</li><li>Single key can бути archived / destroyed</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vote-authorize-withdrawer-checked</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    VOTE_PUBKEY</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    current-withdrawer-keypair.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SQUAD_VAULT_ADDRES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">S</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="squads-costs" tabindex="-1">Squads costs <a class="header-anchor" href="#squads-costs" aria-label="Permalink to &quot;Squads costs&quot;">​</a></h2><ul><li>One-time vault creation: ~0.01 SOL rent</li><li>Per TX: standard fees (5000 lamports base + small extras для multisig logic)</li><li>Negligible для validator economics</li></ul><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,50)),n(i,{data:e}),a[1]||(a[1]=s('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#s"><code>Squads</code></a>, <a href="/glossary#m"><code>Multisig</code></a>, <a href="/glossary#v"><code>Vault account</code></a>, <a href="/glossary#t"><code>Threshold signing</code></a>, <a href="/glossary#n"><code>N-of-M</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.squads.so" target="_blank" rel="noreferrer">Squads documentation</a></li><li><a href="https://github.com/Squads-Protocol/v4/tree/main/audits" target="_blank" rel="noreferrer">Squads V4 audit</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-8/6-kernel-tuning">← 6. Kernel tuning</a> | <strong>Наступне:</strong> <a href="/module-8/8-monitoring-stack">8. Monitoring stack →</a></p>',6))])}}});export{p as __pageData,c as default};
